    <style type="text/css">
        body {
            background-color: #f1f1f1;
            font-size: 12px;
            color: #333;
            font-family: Helvetica Neue, Helvetica, sans-serif
        }

        uni-view,
        uni-scroll-view,
        uni-swiper,
        uni-button,
        uni-input,
        uni-textarea,
        uni-label,
        uni-navigator,
        uni-image {
            box-sizing: border-box
        }

        .round {
            border-radius: 2173px
        }

        .radius {
            border-radius: 2px
        }

        /* ==================
          图片
 ==================== */
        uni-image {
            max-width: 100%;
            display: inline-block;
            position: relative;
            z-index: 0
        }

        uni-image.loading::before {
            content: "";
            background-color: #f5f5f5;
            display: block;
            position: absolute;
            width: 100%;
            height: 100%;
            z-index: -2
        }

        uni-image.loading::after {
            content: "\e7f1";
            font-family: cuIcon;
            position: absolute;
            top: 0;
            left: 0;
            width: 13px;
            height: 13px;
            line-height: 13px;
            right: 0;
            bottom: 0;
            z-index: -1;
            font-size: 13px;
            margin: auto;
            color: #ccc;
            -webkit-animation: cuIcon-spin 2s infinite linear;
            animation: cuIcon-spin 2s infinite linear;
            display: block
        }

        .response {
            width: 100%
        }

        /* ==================
         开关
 ==================== */
        uni-switch,
        uni-checkbox,
        uni-radio {
            position: relative
        }

        uni-switch::after,
        uni-switch::before {
            font-family: cuIcon;
            content: "\e645";
            position: absolute;
            color: #fff !important;
            top: 0;
            left: 0px;
            font-size: 11px;
            line-height: 26px;
            width: 50%;
            text-align: center;
            pointer-events: none;
            -webkit-transform: scale(0);
            transform: scale(0);
            transition: all .3s ease-in-out 0s;
            z-index: 9;
            bottom: 0;
            height: 26px;
            margin: auto
        }

        uni-switch::before {
            content: "\e646";
            right: 0;
            -webkit-transform: scale(1);
            transform: scale(1);
            left: auto
        }

        uni-switch[checked]::after,
        uni-switch.checked::after {
            -webkit-transform: scale(1);
            transform: scale(1)
        }

        uni-switch[checked]::before,
        uni-switch.checked::before {
            -webkit-transform: scale(0);
            transform: scale(0)
        }

        uni-radio::before,
        uni-checkbox::before {
            font-family: cuIcon;
            content: "\e645";
            position: absolute;
            color: #fff !important;
            top: 50%;
            margin-top: -8px;
            right: 5px;
            font-size: 13px;
            line-height: 16px;
            pointer-events: none;
            -webkit-transform: scale(1);
            transform: scale(1);
            transition: all .3s ease-in-out 0s;
            z-index: 9
        }

        uni-radio .wx-radio-input,
        uni-checkbox .wx-checkbox-input,
        uni-radio .uni-radio-input,
        uni-checkbox .uni-checkbox-input {
            margin: 0;
            width: 24px;
            height: 24px
        }

        uni-checkbox.round .wx-checkbox-input,
        uni-checkbox.round .uni-checkbox-input {
            border-radius: 43px
        }

        uni-switch[checked]::before {
            -webkit-transform: scale(0);
            transform: scale(0)
        }

        uni-switch .wx-switch-input,
        uni-switch .uni-switch-input {
            border: none;
            padding: 0 24px;
            width: 48px;
            height: 26px;
            margin: 0;
            border-radius: 43px
        }

        uni-switch .wx-switch-input:not([class*="bg-"]),
        uni-switch .uni-switch-input:not([class*="bg-"]) {
            background: #8799a3 !important
        }

        uni-switch .wx-switch-input::after,
        uni-switch .uni-switch-input::after {
            margin: auto;
            width: 26px;
            height: 26px;
            border-radius: 43px;
            left: 0px;
            top: 0px;
            bottom: 0px;
            position: absolute;
            -webkit-transform: scale(.9);
            transform: scale(.9);
            transition: all .1s ease-in-out 0s
        }

        uni-switch .wx-switch-input.wx-switch-input-checked::after,
