        /* ==================
          边框
 ==================== */
        /* -- 实线 -- */
        .solid,
        .solid-top,
        .solid-right,
        .solid-bottom,
        .solid-left,
        .solids,
        .solids-top,
        .solids-right,
        .solids-bottom,
        .solids-left,
        .dashed,
        .dashed-top,
        .dashed-right,
        .dashed-bottom,
        .dashed-left {
            position: relative
        }

        .solid::after,
        .solid-top::after,
        .solid-right::after,
        .solid-bottom::after,
        .solid-left::after,
        .solids::after,
        .solids-top::after,
        .solids-right::after,
        .solids-bottom::after,
        .solids-left::after,
        .dashed::after,
        .dashed-top::after,
        .dashed-right::after,
        .dashed-bottom::after,
        .dashed-left::after {
            content: " ";
            width: 200%;
            height: 200%;
            position: absolute;
            top: 0;
            left: 0;
            border-radius: inherit;
            -webkit-transform: scale(.5);
            transform: scale(.5);
            -webkit-transform-origin: 0 0;
            transform-origin: 0 0;
            pointer-events: none;
            box-sizing: border-box
        }

        .solid::after {
            border: 1px solid rgba(0, 0, 0, .1)
        }

        .solid-top::after {
            border-top: 1px solid rgba(0, 0, 0, .1)
        }

        .solid-right::after {
            border-right: 1px solid rgba(0, 0, 0, .1)
        }

        .solid-bottom::after {
            border-bottom: 1px solid rgba(0, 0, 0, .1)
        }

        .solid-left::after {
            border-left: 1px solid rgba(0, 0, 0, .1)
        }

        .solids::after {
            border: 3px solid #eee
        }

        .solids-top::after {
            border-top: 3px solid #eee
        }

        .solids-right::after {
            border-right: 3px solid #eee
        }

        .solids-bottom::after {
            border-bottom: 3px solid #eee
        }

        .solids-left::after {
            border-left: 3px solid #eee
        }

        /* -- 虚线 -- */
        .dashed::after {
            border: 1px dashed #ddd
        }

        .dashed-top::after {
            border-top: 1px dashed #ddd
        }

        .dashed-right::after {
            border-right: 1px dashed #ddd
        }

        .dashed-bottom::after {
            border-bottom: 1px dashed #ddd
        }

        .dashed-left::after {
            border-left: 1px dashed #ddd
        }

        /* -- 阴影 -- */
        .shadow[class*="white"] {
            --ShadowSize: 0 1px 2px
        }

        .shadow-lg {
            --ShadowSize: 0px 17px 43px 0px
        }

        .shadow-warp {
            position: relative;
            box-shadow: 0 0 4px rgba(0, 0, 0, .1)
        }

        .shadow-warp:before,
        .shadow-warp:after {
            position: absolute;
            content: "";
            top: 8px;
            bottom: 13px;
            left: 8px;
            width: 50%;
            box-shadow: 0 13px 8px rgba(0, 0, 0, .2);
            -webkit-transform: rotate(-3deg);
            transform: rotate(-3deg);
            z-index: -1
        }

        .shadow-warp:after {
            right: 8px;
            left: auto;
            -webkit-transform: rotate(3deg);
            transform: rotate(3deg)
        }

        .shadow-blur {
            position: relative
        }

        .shadow-blur::before {
            content: "";
            display: block;
            background: inherit;
            -webkit-filter: blur(4px);
            filter: blur(4px);
            position: absolute;
            width: 100%;
            height: 100%;
            top: 4px;
            left: 4px;
            z-index: -1;
            opacity: .4;
            -webkit-transform-origin: 0 0;
            transform-origin: 0 0;
            border-radius: inherit;
            -webkit-transform: scale(1);
            transform: scale(1)
        }

        /* ==================
          按钮
 ==================== */
        .cu-btn {
            position: relative;
            border: 0px;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            box-sizing: border-box;
            padding: 0 13px;
            font-size: 12px;
            height: 27px;
            line-height: 1;
            text-align: center;
            text-decoration: none;
            overflow: visible;
            margin-left: 0;
            -webkit-transform: translate(0px, 0px);
            transform: translate(0px, 0px);
            margin-right: 0
        }

        .cu-btn::after {
            display: none
        }

        .cu-btn:not([class*="bg-"]) {
            background-color: #f0f0f0
        }

        .cu-btn[class*="line"] {
            background-color: initial
        }

        .cu-btn[class*="line"]::after {
            content: " ";
            display: block;
            width: 200%;
            height: 200%;
            position: absolute;
            top: 0;
            left: 0;
            border: 1px solid currentColor;
            -webkit-transform: scale(.5);
            transform: scale(.5);
            -webkit-transform-origin: 0 0;
            transform-origin: 0 0;
            box-sizing: border-box;
            border-radius: 5px;
            z-index: 1;
            pointer-events: none
        }

        .cu-btn.round[class*="line"]::after {
            border-radius: 434px
        }

        .cu-btn[class*="lines"]::after {
            border: 2px solid currentColor
        }

        .cu-btn[class*="bg-"]::after {
            display: none
        }

        .cu-btn.sm {
            padding: 0 8px;
            font-size: 8px;
            height: 20px
        }

        .cu-btn.lg {
            padding: 0 17px;
            font-size: 13px;
            height: 34px
        }

        .cu-btn.cuIcon.sm {
            width: 20px;
            height: 20px
        }

        .cu-btn.cuIcon {
            width: 27px;
            height: 27px;
            border-radius: 217px;
            padding: 0
        }

        uni-button.cuIcon.lg {
            width: 34px;
            height: 34px
        }

        .cu-btn.shadow-blur::before {
            top: 1px;
            left: 1px;
            -webkit-filter: blur(2px);
            filter: blur(2px);
            opacity: .6
        }

        .cu-btn.button-hover {
            -webkit-transform: translate(1px, 1px);
            transform: translate(1px, 1px)
        }

        .block {
            display: block
        }

        .cu-btn.block {
            display: flex
        }

        .cu-btn[disabled] {
            opacity: .6;
            color: #fff
        }

        /* ==================
          徽章
 ==================== */
        .cu-tag {
            font-size: 10px;
            vertical-align: middle;
            position: relative;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            box-sizing: border-box;
            padding: 0px 6px;
            height: 20px;
            font-family: Helvetica Neue, Helvetica, sans-serif;
            white-space: nowrap
        }

        .cu-tag:not([class*="bg"]):not([class*="line"]) {
            background-color: #f1f1f1
        }

        .cu-tag[class*="line-"]::after {
            content: " ";
            width: 200%;
            height: 200%;
            position: absolute;
            top: 0;
            left: 0;
            border: 1px solid currentColor;
            -webkit-transform: scale(.5);
            transform: scale(.5);
            -webkit-transform-origin: 0 0;
            transform-origin: 0 0;
            box-sizing: border-box;
            border-radius: inherit;
            z-index: 1;
            pointer-events: none
        }

        .cu-tag.radius[class*="line"]::after {
            border-radius: 5px
        }

        .cu-tag.round[class*="line"]::after {
            border-radius: 434px
        }

        .cu-tag[class*="line-"]::after {
            border-radius: 0
        }

        .cu-tag + .cu-tag {
            margin-left: 4px
        }

        .cu-tag.sm {
            font-size: 8px;
            padding: 0px 5px;
            height: 13px
        }

        .cu-capsule {
            display: inline-flex;
            vertical-align: middle
        }

        .cu-capsule + .cu-capsule {
            margin-left: 4px
        }

        .cu-capsule .cu-tag {
            margin: 0
        }

        .cu-capsule .cu-tag[class*="line-"]:last-child::after {
            border-left: 0px solid transparent
        }

        .cu-capsule .cu-tag[class*="line-"]:first-child::after {
            border-right: 0px solid transparent
        }

        .cu-capsule.radius .cu-tag:first-child {
            border-top-left-radius: 2px;
            border-bottom-left-radius: 2px
        }

        .cu-capsule.radius .cu-tag:last-child::after,
        .cu-capsule.radius .cu-tag[class*="line-"] {
            border-top-right-radius: 5px;
            border-bottom-right-radius: 5px
        }

        .cu-capsule.round .cu-tag:first-child {
            border-top-left-radius: 86px;
            border-bottom-left-radius: 86px;
            text-indent: 1px
        }

        .cu-capsule.round .cu-tag:last-child::after,
        .cu-capsule.round .cu-tag:last-child {
            border-top-right-radius: 86px;
            border-bottom-right-radius: 86px;
            text-indent: -1px
        }

        .cu-tag.badge {
            border-radius: 86px;
            position: absolute;
            top: -4px;
            right: -4px;
            font-size: 8px;
            padding: 0px 4px;
            height: 12px;
            color: #fff
        }

        .cu-tag.badge:not([class*="bg-"]) {
            background-color: #dd514c
        }

        .cu-tag:empty:not([class*="cuIcon-"]) {
            padding: 0px;
            width: 6px;
            height: 6px;
            top: -1px;
            right: -1px
        }

        .cu-tag[class*="cuIcon-"] {
            width: 13px;
            height: 13px;
            top: -1px;
            right: -1px
        }

        /* ==================
          头像
 ==================== */
        .cu-avatar {
            font-variant: small-caps;
            margin: 0;
            padding: 0;
            display: inline-flex;
            text-align: center;
            justify-content: center;
            align-items: center;
            background-color: #ccc;
            color: #fff;
            white-space: nowrap;
            position: relative;
            width: 27px;
            height: 27px;
            background-size: cover;
            background-position: 50%;
            vertical-align: middle;
            font-size: 1.5em
        }

        .cu-avatar.sm {
            width: 20px;
            height: 20px;
            font-size: 1em
        }

        .cu-avatar.lg {
            width: 41px;
            height: 41px;
            font-size: 2em
        }

        .cu-avatar.xl {
            width: 55px;
            height: 55px;
            font-size: 2.5em
        }

        .cu-avatar .avatar-text {
            font-size: .4em
        }

        .cu-avatar-group {
            direction: rtl;
            unicode-bidi: bidi-override;
            padding: 0 4px 0 17px;
            display: inline-block
        }

        .cu-avatar-group .cu-avatar {
            margin-left: -13px;
            border: 1px solid #f1f1f1;
            vertical-align: middle
        }

        .cu-avatar-group .cu-avatar.sm {
            margin-left: -8px;
            border: 1px solid #f1f1f1
        }

        /* ==================
         进度条
 ==================== */
        .cu-progress {
            overflow: hidden;
            height: 12px;
            background-color: #ebeef5;
            display: inline-flex;
            align-items: center;
            width: 100%
        }

        .cu-progress + uni-view,
        .cu-progress + uni-text {
            line-height: 1
        }

        .cu-progress.xs {
            height: 4px
        }

        .cu-progress.sm {
            height: 8px
        }

        .cu-progress uni-view {
            width: 0;
            height: 100%;
            align-items: center;
            display: flex;
            justify-items: flex-end;
            justify-content: space-around;
            font-size: 8px;
            color: #fff;
            transition: width .6s ease
        }

        .cu-progress uni-text {
            align-items: center;
            display: flex;
            font-size: 8px;
            color: #333;
            text-indent: 4px
        }

        .cu-progress.text-progress {
            padding-right: 26px
        }

        .cu-progress.striped uni-view {
            background-image: linear-gradient(45deg, hsla(0, 0%, 100%, .15) 25%, transparent 0, transparent 50%, hsla(0, 0%, 100%, .15) 0, hsla(0, 0%, 100%, .15) 75%, transparent 0, transparent);
            background-size: 31px 31px
        }

        .cu-progress.active uni-view {
            -webkit-animation: progress-stripes 2s linear infinite;
            animation: progress-stripes 2s linear infinite
        }

        @-webkit-keyframes progress-stripes {
            from {
                background-position: 31px 0
            }
            to {
                background-position: 0 0
            }
        }

        @keyframes progress-stripes {
            from {
                background-position: 31px 0
            }
            to {
                background-position: 0 0
            }
        }

        /* ==================
          加载
 ==================== */
        .cu-load {
            display: block;
            line-height: 3em;
            text-align: center
        }

        .cu-load::before {
            font-family: cuIcon;
            display: inline-block;
            margin-right: 2px
        }

        .cu-load.loading::before {
            content: "\e67a";
            -webkit-animation: cuIcon-spin 2s infinite linear;
            animation: cuIcon-spin 2s infinite linear
        }

        .cu-load.loading::after {
            content: "加载中..."
        }

        .cu-load.over::before {
            content: "\e64a"
        }

        .cu-load.over::after {
            content: "没有更多了"
        }

        .cu-load.erro::before {
            content: "\e658"
        }

        .cu-load.erro::after {
            content: "加载失败"
        }

        .cu-load.load-cuIcon::before {
            font-size: 13px
        }

        .cu-load.load-cuIcon::after {
            display: none
        }

        .cu-load.load-cuIcon.over {
            display: none
        }

        .cu-load.load-modal {
            position: fixed;
            top: 0;
            right: 0;
            bottom: 60px;
            left: 0;
            margin: auto;
            width: 113px;
            height: 113px;
            background-color: #fff;
            border-radius: 4px;
            box-shadow: 0 0 0px 869px rgba(0, 0, 0, .5);
            display: flex;
            align-items: center;
            flex-direction: column;
            justify-content: center;
            font-size: 12px;
            z-index: 9999;
            line-height: 2.4em
        }

        .cu-load.load-modal [class*="cuIcon-"] {
            font-size: 26px
        }

        .cu-load.load-modal uni-image {
            width: 30px;
            height: 30px
        }

        .cu-load.load-modal::after {
            content: "";
            position: absolute;
            background-color: #fff;
            border-radius: 50%;
            width: 86px;
            height: 86px;
            font-size: 10px;
            border-top: 2px solid rgba(0, 0, 0, .05);
            border-right: 2px solid rgba(0, 0, 0, .05);
            border-bottom: 2px solid rgba(0, 0, 0, .05);
            border-left: 2px solid #f37b1d;
            -webkit-animation: cuIcon-spin 1s infinite linear;
            animation: cuIcon-spin 1s infinite linear;
            z-index: -1
        }

        .load-progress {
            pointer-events: none;
            top: 0;
            position: fixed;
            width: 100%;
            left: 0;
            z-index: 2000
        }

        .load-progress.hide {
            display: none
        }

        .load-progress .load-progress-bar {
            position: relative;
            width: 100%;
            height: 1px;
            overflow: hidden;
            transition: all .2s ease 0s
        }

        .load-progress .load-progress-spinner {
            position: absolute;
            top: 4px;
            right: 4px;
            z-index: 2000;
            display: block
        }

        .load-progress .load-progress-spinner::after {
            content: "";
            display: block;
            width: 10px;
            height: 10px;
            -webkit-box-sizing: border-box;
            box-sizing: border-box;
            border: solid 1px transparent;
            border-top-color: inherit;
            border-left-color: inherit;
            border-radius: 50%;
            -webkit-animation: load-progress-spinner .4s linear infinite;
            animation: load-progress-spinner .4s linear infinite
        }

        @-webkit-keyframes load-progress-spinner {
            0% {
                -webkit-transform: rotate(0);
                transform: rotate(0)
            }
            100% {
                -webkit-transform: rotate(1turn);
                transform: rotate(1turn)
            }
        }

        @keyframes load-progress-spinner {
            0% {
                -webkit-transform: rotate(0);
                transform: rotate(0)
            }
            100% {
                -webkit-transform: rotate(1turn);
                transform: rotate(1turn)
            }
        }

