        /* ==================
         时间轴
 ==================== */
        .cu-timeline {
            display: block;
            background-color: #fff
        }

        .cu-timeline .cu-time {
            width: 52px;
            text-align: center;
            padding: 8px 0;
            font-size: 11px;
            color: #888;
            display: block
        }

        .cu-timeline > .cu-item {
            padding: 13px 13px 13px 52px;
