        }

        .cu-timeline > .cu-item::after {
            content: "";
            display: block;
            position: absolute;
            width: 1px;
            background-color: #ddd;
            left: 26px;
            height: 100%;
            top: 0;
            z-index: 8
        }

        .cu-timeline > .cu-item::before {
            font-family: cuIcon;
            display: block;
            position: absolute;
            top: 15px;
            z-index: 9;
            background-color: #fff;
            width: 21px;
            height: 21px;
            text-align: center;
            border: none;
            line-height: 21px;
            left: 15px
        }

        .cu-timeline > .cu-item:not([class*="cuIcon-"])::before {
            content: "\e763"
        }

        .cu-timeline > .cu-item[class*="cuIcon-"]::before {
            background-color: #fff;
            width: 21px;
            height: 21px;
            text-align: center;
            border: none;
            line-height: 21px;
            left: 15px
