            padding: 13px 13px 30px;
            position: relative
        }

        .cu-chat .cu-item > .cu-avatar {
            width: 34px;
            height: 34px
        }

        .cu-chat .cu-item > .main {
            max-width: calc(100% - 113px);
            margin: 0 17px;
            display: flex;
            align-items: center
        }

        .cu-chat .cu-item > uni-image {
            height: 139px
        }

        .cu-chat .cu-item > .main .content {
            padding: 8px;
            border-radius: 2px;
            display: inline-flex;
            max-width: 100%;
            align-items: center;
            font-size: 13px;
            position: relative;
            min-height: 34px;
            line-height: 17px;
            text-align: left
        }

        .cu-chat .cu-item > .main .content:not([class*="bg-"]) {
            background-color: #fff;
            color: #333
        }

        .cu-chat .cu-item .date {
            position: absolute;
            font-size: 10px;
            color: #8799a3;
            width: calc(100% - 139px);
            bottom: 8px;
            left: 69px
        }

        .cu-chat .cu-item .action {
            padding: 0 13px;
            display: flex;
            align-items: center
        }

        .cu-chat .cu-item > .main .content::after {
            content: "";
            top: 11px;
            -webkit-transform: rotate(45deg);
            transform: rotate(45deg);
            position: absolute;
            z-index: 100;
            display: inline-block;
            overflow: hidden;
            width: 10px;
            height: 10px;
            left: -5px;
            right: auto;
            background-color: inherit
        }

        .cu-chat .cu-item.self > .main .content::after {
            left: auto;
            right: -5px
        }

        .cu-chat .cu-item > .main .content::before {
            content: "";
            top: 13px;
            -webkit-transform: rotate(45deg);
            transform: rotate(45deg);
            position: absolute;
            z-index: -1;
            display: inline-block;
            overflow: hidden;
            width: 10px;
            height: 10px;
            left: -5px;
            right: auto;
            background-color: inherit;
            -webkit-filter: blur(2px);
            filter: blur(2px);
            opacity: .3
        }

        .cu-chat .cu-item > .main .content:not([class*="bg-"])::before {
            background-color: #333;
            opacity: .1
        }

        .cu-chat .cu-item.self > .main .content::before {
            left: auto;
            right: -5px
        }

        .cu-chat .cu-item.self {
            justify-content: flex-end;
            text-align: right
        }

        .cu-chat .cu-info {
            display: inline-block;
            margin: 8px auto;
            font-size: 10px;
