        .cu-form-group uni-picker::after {
            font-family: cuIcon;
            display: block;
            content: "\e6a3";
            position: absolute;
            font-size: 14px;
            color: #8799a3;
            line-height: 43px;
            width: 26px;
            text-align: center;
            top: 0;
            bottom: 0;
