        /* ==================
         模态窗口
 ==================== */
        .cu-modal {
            position: fixed;
            top: 0;
            right: 0;
            bottom: 0;
            left: 0;
            z-index: 1110;
            opacity: 0;
            outline: 0;
            text-align: center;
            -ms-transform: scale(1.185);
            -webkit-transform: scale(1.185);
            transform: scale(1.185);
            -webkit-backface-visibility: hidden;
            backface-visibility: hidden;
            -webkit-perspective: 869px;
            perspective: 869px;
            background: rgba(0, 0, 0, .6);
            transition: all .3s ease-in-out 0s;
            pointer-events: none
        }

        .cu-modal::before {
            content: "\200B";
            display: inline-block;
            height: 100%;
            vertical-align: middle
        }

        .cu-modal.show {
            opacity: 1;
            transition-duration: .3s;
            -ms-transform: scale(1);
            -webkit-transform: scale(1);
            transform: scale(1);
            overflow-x: hidden;
            overflow-y: auto;
            pointer-events: auto
        }

        .cu-dialog {
            position: relative;
            display: inline-block;
            vertical-align: middle;
            margin-left: auto;
            margin-right: auto;
            width: 295px;
            max-width: 100%;
            background-color: #f8f8f8;
            border-radius: 4px;
            overflow: hidden
        }

        .cu-modal.bottom-modal::before {
            vertical-align: bottom
        }

        .cu-modal.bottom-modal .cu-dialog {
            width: 100%;
            border-radius: 0
        }

        .cu-modal.bottom-modal {
            margin-bottom: -434px
        }

        .cu-modal.bottom-modal.show {
            margin-bottom: 0
        }

        .cu-modal.drawer-modal {
            -webkit-transform: scale(1);
            transform: scale(1);
            display: flex
        }

        .cu-modal.drawer-modal .cu-dialog {
            height: 100%;
            min-width: 86px;
            border-radius: 0;
            margin: initial;
            transition-duration: .3s
        }

        .cu-modal.drawer-modal.justify-start .cu-dialog {
            -webkit-transform: translateX(-100%);
            transform: translateX(-100%)
        }

        .cu-modal.drawer-modal.justify-end .cu-dialog {
            -webkit-transform: translateX(100%);
            transform: translateX(100%)
        }

        .cu-modal.drawer-modal.show .cu-dialog {
            -webkit-transform: translateX(0);
            transform: translateX(0)
        }

        .cu-modal .cu-dialog > .cu-bar:first-child .action {
            min-width: 43px;
            margin-right: 0;
            min-height: 43px
        }

        /* ==================
         轮播
 ==================== */
        uni-swiper .a-swiper-dot {
            display: inline-block;
            width: 6px;
            height: 6px;
            background: rgba(0, 0, 0, .3);
            border-radius: 50%;
            vertical-align: middle
        }

        uni-swiper[class*="-dot"] .wx-swiper-dots,
        uni-swiper[class*="-dot"] .a-swiper-dots,
        uni-swiper[class*="-dot"] .uni-swiper-dots {
            display: flex;
            align-items: center;
            width: 100%;
            justify-content: center
        }

        uni-swiper.square-dot .wx-swiper-dot,
        uni-swiper.square-dot .a-swiper-dot,
        uni-swiper.square-dot .uni-swiper-dot {
            background-color: #fff;
            opacity: .4;
            width: 4px;
            height: 4px;
            border-radius: 8px;
            margin: 0 3px !important
        }

        uni-swiper.square-dot .wx-swiper-dot.wx-swiper-dot-active,
        uni-swiper.square-dot .a-swiper-dot.a-swiper-dot-active,
        uni-swiper.square-dot .uni-swiper-dot.uni-swiper-dot-active {
            opacity: 1;
            width: 13px
        }

        uni-swiper.round-dot .wx-swiper-dot,
        uni-swiper.round-dot .a-swiper-dot,
        uni-swiper.round-dot .uni-swiper-dot {
            width: 4px;
            height: 4px;
            position: relative;
            margin: 1px 3px !important
        }

        uni-swiper.round-dot .wx-swiper-dot.wx-swiper-dot-active::after,
        uni-swiper.round-dot .a-swiper-dot.a-swiper-dot-active::after,
        uni-swiper.round-dot .uni-swiper-dot.uni-swiper-dot-active::after {
            content: "";
            position: absolute;
            width: 4px;
            height: 4px;
            top: 0px;
            left: 0px;
            right: 0;
            bottom: 0;
            margin: auto;
            background-color: #fff;
            border-radius: 8px
        }

        uni-swiper.round-dot .wx-swiper-dot.wx-swiper-dot-active,
        uni-swiper.round-dot .a-swiper-dot.a-swiper-dot-active,
        uni-swiper.round-dot .uni-swiper-dot.uni-swiper-dot-active {
            width: 7px;
            height: 7px
        }

        .screen-swiper {
            /* min-height: 375upx; */
        }

        .screen-swiper uni-image,
        .screen-swiper uni-video,
        .swiper-item uni-image,
        .swiper-item uni-video {
            width: 100%;
            display: block;
            height: 100%;
            margin: 0;
            pointer-events: none
        }

        .card-swiper {
            height: 182px !important
        }

        .card-swiper uni-swiper-item {
            width: 265px !important;
            left: 30px;
            box-sizing: border-box;
            padding: 17px 0px 30px;
            overflow: initial
        }

        .card-swiper uni-swiper-item .swiper-item {
            width: 100%;
            display: block;
            height: 100%;
            border-radius: 4px;
            -webkit-transform: scale(.9);
            transform: scale(.9);
            transition: all .2s ease-in 0s;
            overflow: hidden
        }

        .card-swiper uni-swiper-item.cur .swiper-item {
            -webkit-transform: none;
            transform: none;
            transition: all .2s ease-in 0s
        }

        .tower-swiper {
            height: 182px;
            position: relative;
            max-width: 326px;
            overflow: hidden
        }

        .tower-swiper .tower-item {
            position: absolute;
            width: 130px;
            height: 165px;
            top: 0;
            bottom: 0;
            left: 50%;
            margin: auto;
            transition: all .2s ease-in 0s;
            opacity: 1
        }

        .tower-swiper .tower-item.none {
            opacity: 0
        }

        .tower-swiper .tower-item .swiper-item {
            width: 100%;
            height: 100%;
            border-radius: 2px;
            overflow: hidden
        }

        /* ==================
          步骤条
 ==================== */
        .cu-steps {
            display: flex
        }

        uni-scroll-view.cu-steps {
            display: block;
            white-space: nowrap
        }

        uni-scroll-view.cu-steps .cu-item {
            display: inline-block
        }

        .cu-steps .cu-item {
            flex: 1;
            text-align: center;
            position: relative;
            min-width: 43px
        }

        .cu-steps .cu-item:not([class*="text-"]) {
            color: #8799a3
        }

        .cu-steps .cu-item [class*="cuIcon-"],
        .cu-steps .cu-item .num {
            display: block;
            font-size: 17px;
            line-height: 34px
        }

        .cu-steps .cu-item::before,
        .cu-steps .cu-item::after,
        .cu-steps.steps-arrow .cu-item::before,
        .cu-steps.steps-arrow .cu-item::after {
            content: "";
            display: block;
            position: absolute;
            height: 0;
            width: calc(100% - 34px);
            border-bottom: 1px solid #ccc;
            left: calc(0px - (100% - 34px) / 2);
            top: 17px;
            z-index: 0
        }

        .cu-steps.steps-arrow .cu-item::before,
        .cu-steps.steps-arrow .cu-item::after {
            content: "\e6a3";
            font-family: cuIcon;
            height: 13px;
            border-bottom-width: 0;
            line-height: 13px;
            top: 0;
            bottom: 0;
            margin: auto;
            color: #ccc
        }

        .cu-steps.steps-bottom .cu-item::before,
        .cu-steps.steps-bottom .cu-item::after {
            bottom: 17px;
            top: auto
        }

        .cu-steps .cu-item::after {
            border-bottom: 1px solid currentColor;
            width: 0;
            transition: all .3s ease-in-out 0s
        }

        .cu-steps .cu-item[class*="text-"]::after {
            width: calc(100% - 34px);
            color: currentColor
        }

        .cu-steps .cu-item:first-child::before,
        .cu-steps .cu-item:first-child::after {
            display: none
        }

        .cu-steps .cu-item .num {
            width: 17px;
            height: 17px;
            border-radius: 50%;
            line-height: 17px;
            margin: 8px auto;
            font-size: 10px;
            border: 1px solid currentColor;
            position: relative;
            overflow: hidden
        }

        .cu-steps .cu-item[class*="text-"] .num {
            background-color: currentColor
        }

        .cu-steps .cu-item .num::before,
        .cu-steps .cu-item .num::after {
            content: attr(data-index);
            position: absolute;
            left: 0;
            right: 0;
            top: 0;
            bottom: 0;
            margin: auto;
            transition: all .3s ease-in-out 0s;
            -webkit-transform: translateY(0px);
            transform: translateY(0px)
        }

        .cu-steps .cu-item[class*="text-"] .num::before {
            -webkit-transform: translateY(-17px);
            transform: translateY(-17px);
            color: #fff
        }

        .cu-steps .cu-item .num::after {
            -webkit-transform: translateY(17px);
            transform: translateY(17px);
            color: #fff;
            transition: all .3s ease-in-out 0s
        }

        .cu-steps .cu-item[class*="text-"] .num::after {
            content: "\e645";
            font-family: cuIcon;
            color: #fff;
            -webkit-transform: translateY(0px);
            transform: translateY(0px)
        }

        .cu-steps .cu-item[class*="text-"] .num.err::after {
            content: "\e646"
        }

