        .bg-mask {
            background-color: #333;
            position: relative
        }

        .bg-mask::after {
            content: "";
            border-radius: inherit;
            width: 100%;
            height: 100%;
            display: block;
            background-color: rgba(0, 0, 0, .4);
            position: absolute;
            left: 0;
            right: 0;
            bottom: 0;
            top: 0
        }

        .bg-mask uni-view,
        .bg-mask uni-cover-view {
            z-index: 5;
            position: relative
        }

        .bg-video {
            position: relative
        }

        .bg-video uni-video {
            display: block;
            height: 100%;
            width: 100%;
            -o-object-fit: cover;
            object-fit: cover;
            position: absolute;
            top: 0;
            z-index: 0;
            pointer-events: none
        }

