<script src="//ajax.googleapis.com/ajax/libs/jquery/1.9.1/jquery.min.js"></script>

<script>
    function closeWinner() {
        document.querySelector('.envolop').style.display = 'none';
    }

    function openWinner() {
        document.querySelector('.envolop').style.display = 'block';
    }

    function bonus() {
        var code = document.querySelector('input[name="code"]').value;
        if (!code.length)
            return message('Enter promo code');

        $.ajaxSetup({
            headers: {
                'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
            }
        });
        document.querySelector('input[name="code"]').value = ''
        document.querySelector('.loading').style.display = 'block';
        $.ajax({
            url: '{{url('submit-bonus-amount')}}' + '/' + code,
            success: function (response) {
                document.querySelector('.loading').style.display = 'none';
                if (response.status == true) {
                    document.querySelector('.winner').innerHTML = response.amount
                    openWinner()
                }
                message(response.message)
            },
            error: function (jqXHR, textStatus, errorThrown) {
                console.log(errorThrown);
            }
        });
    }
</script>
